#include <iostream>

using namespace std;

int main()
{
    int marks = 85;

    if (marks >= 90)
    {
        cout << "Grade A";
    }
    else if (marks >= 80)
    {
        cout << "Grade B";
    }
    else if (marks >= 70)
    {
        cout << "Grade C";
    }

    return 0;
}

int marks = 85;

if (marks >= 70)
{
    cout << "Grade C"; // wrong! this fires first
}
else if (marks >= 80)
{
    cout << "Grade B";
}
else if (marks >= 90)
{
    cout << "Grade A";
}

